from logging.handlers import RotatingFileHandler
from pathlib import Path
import stat

# Secure log configuration
LOG_DIR = Path("/var/log/myapp")
LOG_FILE = LOG_DIR / "application.log"
LOG_MAX_SIZE = 10 * 1024 * 1024  # 10MB
LOG_BACKUP_COUNT = 5

# Create log directory with secure permissions
LOG_DIR.mkdir(parents=True, exist_ok=True)
os.chmod(LOG_DIR, stat.S_IRWXU | stat.S_IRGRP | stat.S_IXGRP | stat.S_IROTH | stat.S_IXOTH)

# Configure logging
logger = logging.getLogger("secure_app")
logger.setLevel(logging.INFO)

# Create rotating file handler
handler = RotatingFileHandler(
    LOG_FILE,
    maxBytes=LOG_MAX_SIZE,
    backupCount=LOG_BACKUP_COUNT,
    encoding='utf-8'
)

# Set secure permissions on log file
os.chmod(LOG_FILE, stat.S_IRUSR | stat.S_IWUSR | stat.S_IRGRP | stat.S_IROTH)

# Create formatter
formatter = logging.Formatter(
    '%(asctime)s - %(name)s - %(levelname)s - %(message)s'
)
handler.setFormatter(formatter)

# Add handler to logger
logger.addHandler(handler)

# Secure input validation function
def validate_input(user_input):
    """Validate and sanitize user input"""
    if not isinstance(user_input, str):
        raise ValueError("Input must be a string")
    
    # Remove potentially dangerous characters
    sanitized = user_input.replace('\x00', '').strip()
    
    if len(sanitized) > 1000:  # Prevent overly long inputs
        raise ValueError("Input too long")
    
    return sanitized

# Secure logging function
